def main():
    with open("/workspace/tmp_deepwatch.jsonl") as f:
        examples = [json.loads(line) for line in f]

    patched_count = 0
    for example in examples:
        eid = example["id"]
        if eid in PATCHES:
            patch = PATCHES[eid]
            if "text" in patch:
                example["text"] = patch["text"]
            if "tags" in patch:
                example["tags"] = patch["tags"]
            if "notes" in patch:
                example["notes"] = patch["notes"]
            patched_count += 1

    with open("/workspace/tmp_deepwatch.jsonl", "w") as f:
        for example in examples:
            f.write(json.dumps(example, ensure_ascii=False) + "\n")

    near_approve = sum(1 for e in examples if "near_approve" in e.get("tags", []))
    print(f"Patched {patched_count} examples")
    print(f"Near-approve count: {near_approve}")
    print(f"Total examples: {len(examples)}")

    for e in examples:
        text_words = len(e.get("text", "").split())
        if text_words < 50 or text_words > 300:
            print(f"WARNING: {e['id']} has {text_words} words")

if __name__ == "__main__":
    main()
